+pub struct ViewLine {
+    /// The rendered text for this virtual line.
+    pub text: String,
+    /// The source (logical) line index from the original text.
+    pub source_line: usize,
+    /// True if this is a wrapped continuation of the source line.
+    pub is_wrap: bool,
