+            self.wrap = wrap;
+            self.rebuild();
+        }
+    }
+
+    /// Update viewport width and recompute layout.
+    pub fn set_width(&mut self, width: usize) {
+        if self.width != width {
+            self.width = width;
+            self.rebuild();
+        }
+    }
