+        self.max_width
+    }
+
+    /// Access all virtual lines.
+    #[must_use]
+    pub fn lines(&self) -> &[ViewLine] {
+        &self.lines
+    }
+
+    /// Map a source line index to its first virtual line index.
+    #[must_use]
